import React from 'react'
import PropTypes from 'prop-types'
import * as T from 'three'
import { ComputeShaderPass } from '/src/graphics/gl'
import glslJuliaSpinner from '/src/graphics/gl/sdfs/static/juliaSpinner'

const rescale = 2

export class JuliaSpinner extends React.Component {
    constructor(props) {
        super(props)
        this.container = React.createRef()
    }
    componentDidMount() {
        this.time = 0
        this.camera = new T.PerspectiveCamera(70, this.width / this.height, 1, 1000)

        const phi = 0.5 * Math.PI
        const theta = 0.2 * Math.PI
        this.camera.position.set(
            5 * Math.cos(phi) * Math.sin(theta),
            5 * Math.cos(theta),
            5 * Math.sin(phi) * Math.sin(theta)
        )

        this.camera.lookAt(new T.Vector3(0, 0, 0))
        this.camera.updateMatrix()

        this.uniforms = {
            zoomScale: {
                type: 'f',
                value: 0.4,
            },
            time: {
                type: 'f',
                value: this.time,
            },
            invProjectionMat: {
                type: 'm4',
                value: this.camera.projectionMatrix.invert(),
            },
            cameraMat: {
                type: 'm4',
                value: this.camera.matrix,
            },
        }
        this.collisionPass = new ComputeShaderPass(
            {
                uniforms: this.uniforms,
                fragmentShader: glslJuliaSpinner,
            },
            this.width,
            this.height
        )
        this.container.current.appendChild(this.collisionPass.renderer.domElement)
        this.collisionPass.renderer.domElement.style.transform = `scale(${1 / rescale})`
        const animate = () => {
            if (!this.collisionPass) {
                return
            }
            this.time += 1
            this.uniforms.time.value = this.time / 1e6
            if (this.needsResize) {
                this.resize()
            }
            this.draw()
            requestAnimationFrame(animate)
        }
        animate()
    }
    componentWillUnmount() {
        this.collisionPass.dispose()
        delete this.collisionPass
    }
    render() {
        return (
            <div
                ref={this.container}
                className={`flex items-center justify-center h-24 w-24 ${this.props.className ?? 'h-24 w-24'}`}
            />
        )
    }
    get needsResize() {
        if (!this.collisionPass) {
            return false
        }
        const rendererBounds = this.collisionPass.renderer.domElement.getBoundingClientRect()
        return rendererBounds.width !== this.width || rendererBounds.height !== this.height
    }
    get width() {
        return rescale * this.container.current?.getBoundingClientRect()?.width ?? 0
    }
    get height() {
        return rescale * this.container.current?.getBoundingClientRect()?.height ?? 0
    }
    draw() {
        this.collisionPass.execute(true)
    }
    resize() {
        const { width, height } = this
        this.camera.aspect = width / height
        this.camera.updateProjectionMatrix()

        this.uniforms.invProjectionMat.value = this.camera.projectionMatrix.invert()
        this.collisionPass.resize(width, height)
        this.collisionPass.renderer.domElement.style.transform = `scale(${1 / rescale})`
    }
}

JuliaSpinner.propTypes = {
    className: PropTypes.string,
}
